#!/usr/bin/env python3
"""
Tres ajustes de diseno:
  1) Arregla el selector de estrellas en /p/[slug]/cita/[id] (no se
     coloreaban al hacer click por un problema de especificidad CSS).
  2) Las cards de 'Opiniones de clientes' en el portal ahora son mas
     grandes (rectangulo con mas padding) y el vidrio esmerilado pasa
     de un tinte blanco-azulado a un tinte negro/sobrio.
  3) El fondo (circulos difuminados) se oscurece un poco.

Ejecutar desde la raiz del repo (carpeta que contiene 'src' y 'public'):
    python3 apply_review_ui_polish.py
"""

import base64
from pathlib import Path

FILES = {
    'src/components/cita-manage.css': """""",
    'src/components/portal.css': """""",
    'public/images/dark-bg.svg': """""",
}

def main():
    for relpath, b64 in FILES.items():
        p = Path(relpath)
        p.write_bytes(base64.b64decode(b64))
        print(f"escrito: {relpath} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Arreglo selector de estrellas, cards de resenas mas grandes y vidrio sobrio'")
    print("  git push")

if __name__ == "__main__":
    main()